const allItems = $input.all();
const config = $('Set Variables').first().json;
const cutoff = new Date(Date.now() - config.days_back * 24 * 60 * 60 * 1000);

const releases = [];

for (const item of allItems) {
  // /releases?per_page=1 returns an array — take the first (most recent)
  const releaseList = Array.isArray(item.json) ? item.json : [item.json];

  for (const r of releaseList) {
    if (!r.published_at || !r.html_url) continue;
    if (r.draft) continue; // skip drafts only; pre-releases are included (n8n marks stable releases as pre-release on GitHub)
    if (new Date(r.published_at) < cutoff) continue;

    const repo = r.html_url.split('/releases/')[0].replace('https://github.com/', '');
    const body = r.body
      ? r.body.replace(/#{1,6}\s/g, '').replace(/<!--[\s\S]*?-->/g, '').trim().substring(0, 280) + '...'
      : 'No release notes.';

    releases.push({
      repo,
      tag: r.tag_name,
      name: r.name || r.tag_name,
      url: r.html_url,
      published_at: r.published_at,
      body,
      prerelease: r.prerelease
    });
    break; // only take the most recent per repo
  }
}

return [{ json: { releases, release_count: releases.length } }];

const allItems = $input.all();
const config = $('Set Variables').first().json;
const cutoff = new Date(Date.now() - config.days_back * 24 * 60 * 60 * 1000);
const commits = [];

for (const item of allItems) {
  const data = item.json;
  if (!data || data.message === 'Not Found') continue;

  // User/Org events format
  if (data.type) {
    if (data.type !== 'PushEvent') continue;
    if (new Date(data.created_at) < cutoff) continue;
    const actor = data.actor?.login || 'unknown';
    const repoName = data.repo?.name || 'unknown';
    for (const commit of (data.payload?.commits || []).slice(0,3)) {
      commits.push({ author: actor, author_url: `https://github.com/${actor}`, repo: repoName, repo_url: `https://github.com/${repoName}`, message: (commit.message||'').split('\n')[0].substring(0,100), sha: (commit.sha||'').substring(0,7), url: `https://github.com/${repoName}/commit/${commit.sha}`, date: data.created_at });
    }
  }
  // Repo commits format
  else if (data.sha && data.commit) {
    const commitDate = data.commit.author?.date || data.commit.committer?.date;
    if (commitDate && new Date(commitDate) < cutoff) continue;
    const repoBase = (data.html_url||'').split('/commit/')[0];
    const repoPath = repoBase.replace('https://github.com/','');
    commits.push({ author: data.author?.login || data.commit.author?.name || 'unknown', author_url: data.author ? `https://github.com/${data.author.login}` : '#', repo: repoPath, repo_url: repoBase, message: (data.commit.message||'').split('\n')[0].substring(0,100), sha: (data.sha||'').substring(0,7), url: data.html_url||'', date: commitDate||'' });
  }
}

const seen = new Set();
const unique = commits.filter(c => { if(seen.has(c.sha)) return false; seen.add(c.sha); return true; }).slice(0,40);
return [{ json: { commits: unique, commit_count: unique.length } }];

const rawData = $input.first().json;
const html = rawData.data || rawData.body || '';

const repos = [];
let pos = 0;

while (repos.length < 10) {
  const start = html.indexOf('class="Box-row"', pos);
  if (start === -1) break;
  const end = html.indexOf('</article>', start);
  if (end === -1) break;
  pos = end + 10;
  const block = html.substring(start, end);

  const linkMatch = block.match(/href="\/(([\w][\w.-]+)\/([\w][\w.-]+))"/);
  if (!linkMatch) continue;
  const repoPath = linkMatch[1];
  if (['trending','explore','settings','login','signup'].some(s => repoPath.startsWith(s))) continue;

  const descMatch = block.match(/col-9[^"]*"[^>]*>\s*([^<]{3,})/);
  const description = descMatch ? descMatch[1].trim().replace(/\s+/g,' ').substring(0,120) : '';

  const langMatch = block.match(/programmingLanguage"[^>]*>([^<]+)</);
  const language = langMatch ? langMatch[1].trim() : '';

  const starsMatch = block.match(/([\d,]+)\s+stars?\s+today/i);
  const starsToday = starsMatch ? starsMatch[1] : '';

  repos.push({ name: repoPath, url: `https://github.com/${repoPath}`, description, language, stars_today: starsToday });
}

return [{ json: { trending_repos: repos, trending_count: repos.length } }];

const items = $input.all();

const relData = (items.find(i => i.json.releases) || { json: { releases: [], release_count: 0 } }).json;
const cmData = (items.find(i => i.json.commits) || { json: { commits: [], commit_count: 0 } }).json;
const trData = (items.find(i => i.json.trending_repos) || { json: { trending_repos: [], trending_count: 0 } }).json;

const releases = relData.releases || [];
const commits = cmData.commits || [];
const trending = trData.trending_repos || [];

const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
const subject = `\uD83E\uDD16 Weekly GitHub Digest \u2014 ${today}`;

const releasesHtml = releases.length === 0
  ? `<p style='color:#999;font-style:italic'>No new releases this week.</p>`
  : releases.map(r => `<div style='margin-bottom:16px;padding:12px;background:#fafafa;border-left:3px solid #ff6d5a;border-radius:4px'><a href='${r.url}' style='font-weight:600;color:#ff6d5a;text-decoration:none'>${r.repo} ${r.tag}</a><span style='color:#999;font-size:12px;margin-left:8px'>${new Date(r.published_at).toLocaleDateString()}</span><p style='margin:6px 0 0;font-size:13px;color:#555'>${r.body}</p></div>`).join('');

const commitsHtml = commits.length === 0
  ? `<p style='color:#999;font-style:italic'>No recent commits found.</p>`
  : commits.slice(0, 15).map(c => `<div style='margin-bottom:10px;padding:8px 12px;background:#fafafa;border-left:3px solid #6366f1;border-radius:4px'><a href='${c.url}' style='font-size:13px;color:#6366f1;text-decoration:none;font-weight:500'>${c.message}</a><br><span style='font-size:11px;color:#999'>${c.repo} \u00b7 ${c.sha} \u00b7 ${c.author} \u00b7 ${c.date ? new Date(c.date).toLocaleDateString() : ''}</span></div>`).join('');

const trendingHtml = trending.length === 0
  ? `<p style='color:#999;font-style:italic'>Could not load trending repos today.</p>`
  : trending.map((r, i) => `<div style='margin-bottom:10px;padding:8px 12px;background:#fafafa;border-left:3px solid #10b981;border-radius:4px'><span style='color:#999;font-size:11px;margin-right:8px'>#${i+1}</span><a href='${r.url}' style='font-weight:600;color:#10b981;text-decoration:none'>${r.name}</a>${r.language ? `<span style='font-size:11px;color:#999;margin-left:8px'>${r.language}</span>` : ''}${r.stars_today ? `<span style='font-size:11px;color:#f59e0b;margin-left:8px'>\u2605 ${r.stars_today} today</span>` : ''}<br><span style='font-size:12px;color:#666;margin-top:2px'>${r.description || ''}</span></div>`).join('');

const html = `<div style='font-family:sans-serif;max-width:620px;margin:0 auto;padding:24px;color:#333'><h2 style='margin-bottom:4px'>\uD83E\uDD16 Weekly GitHub Digest</h2><p style='color:#aaa;font-size:13px;margin-top:0;margin-bottom:28px'>${today}</p><h3 style='color:#ff6d5a;margin-bottom:14px;padding-bottom:6px;border-bottom:2px solid #ff6d5a'>\uD83D\uDE80 New Releases (${releases.length})</h3>${releasesHtml}<h3 style='color:#6366f1;margin-bottom:14px;padding-bottom:6px;border-bottom:2px solid #6366f1;margin-top:32px'>\uD83D\uDC65 Developer Commits (${commits.length})</h3>${commitsHtml}<h3 style='color:#10b981;margin-bottom:14px;padding-bottom:6px;border-bottom:2px solid #10b981;margin-top:32px'>\uD83D\uDD25 Trending Today (${trending.length})</h3>${trendingHtml}<hr style='border:none;border-top:1px solid #eee;margin:32px 0'><p style='font-size:12px;color:#bbb'>Weekly digest created by Dahiana Porto via N8N</p></div>`;

return [{ json: { html, subject, release_count: releases.length, commit_count: commits.length, trending_count: trending.length } }];
